import { pollAgentEvents } from "../agentEventPoller.js";
import { reportHandoff } from "../analytics.js";
import { runBrowserHandoff } from "../browserHandoff.js";
import { getConfig, hasCredentials } from "../config.js";
import { focusApp, getFrontmostApp } from "../frontmostApp.js";
const START_DATASET_TIMEOUT_MS = 30 * 60 * 1000;
const RESPONSE_HTML = `<html>
<body style="margin:0;background:#f8fafc;color:#0f172a;font-family:system-ui,-apple-system,sans-serif;display:flex;align-items:center;justify-content:center;height:100vh;overflow:hidden">
  <div style="text-align:center;max-width:400px">
    <h1 style="font-size:24px;font-weight:600;margin:0 0 16px 0">Bitfab</h1>
    <p style="margin:0;color:#059669">Labeling complete! You can close this window.</p>
    <button onclick="window.close()" style="margin-top:16px;padding:8px 16px;background:#0f172a;color:white;border:none;border-radius:8px;font-size:14px;font-weight:500;cursor:pointer">Close Window</button>
  </div>
</body>
</html>`;
function parseStatus(raw) {
    return raw === "saved" ? "saved" : "cancelled";
}
function emitJson(event) {
    process.stdout.write(`${JSON.stringify(event)}\n`);
}
/**
 * Open the per-dataset review page and stay alive until the user clicks Done
 * (or cancels). Stdout is a JSON line stream — one line per event:
 *
 *   {"event":"modify","datasetId":"...","ts":"..."}     // non-terminal
 *   {"event":"saved","status":"saved",...}              // terminal
 *   {"event":"cancelled","status":"cancelled"}          // terminal
 *
 * After a terminal event the process exits 0. The calling agent reads stdout
 * incrementally (Claude Code: `run_in_background: true`; Cursor / Codex: each
 * runtime's equivalent of "start a process and tail its output"), reacting
 * to each modify event by doing add/remove work, then continuing to read.
 *
 * Two channels run in parallel:
 *   1. `dataset.start` browser handoff — terminal saved/cancelled signal.
 *   2. `dataset.agent.event` short-poll — non-terminal modify signals.
 *
 * Free-form logs go to stderr so stdout stays a parseable JSONL stream.
 */
export async function runStartDataset(platform, pluginVersion) {
    const args = process.argv.slice(2);
    const functionKey = args[0];
    const datasetId = args[1];
    if (!functionKey || !datasetId) {
        console.error("Usage: startDataset <functionKey> <datasetId>");
        console.error("Both arguments are required.");
        process.exit(1);
    }
    if (!hasCredentials()) {
        console.error(`Not authenticated. Run ${platform.loginHint} first.`);
        process.exit(1);
    }
    const config = getConfig();
    if (!config.apiKey) {
        console.error("API key missing in config.");
        process.exit(1);
    }
    const apiKey = config.apiKey;
    const previousApp = getFrontmostApp();
    const loopbackRoute = {
        path: "/done",
        handle: (params, res, resolve) => {
            res.writeHead(200, { "Content-Type": "text/html" });
            res.end(RESPONSE_HTML);
            resolve({
                status: parseStatus(params.get("status")),
                decision: params.get("decision"),
                labeled: params.get("labeled"),
                total: params.get("total"),
                isFetch: params.get("isFetch") === "true",
            });
        },
    };
    // Run the agent-event poller alongside the browser handoff. Each modify
    // event is emitted to stdout immediately; the loop continues until the
    // handoff returns (terminal Done) or the abort fires.
    const agentAbort = new AbortController();
    const pollerPromise = pollAgentEvents({
        serviceUrl: config.serviceUrl,
        apiKey,
        datasetId,
        abortSignal: agentAbort.signal,
        onEvent: (event) => {
            emitJson({
                event: event.data.action,
                datasetId: event.data.datasetId,
                ts: event.createdAt,
            });
        },
        onError: (err) => {
            console.error(`agent-event poll: ${err.message}`);
        },
    });
    try {
        const { value, wonBy, loopbackAvailable, ticketAvailable } = await runBrowserHandoff({
            serviceUrl: config.serviceUrl,
            ticketKind: "dataset.start",
            ticketBearer: apiKey,
            timeoutMs: START_DATASET_TIMEOUT_MS,
            ticketTtlSeconds: START_DATASET_TIMEOUT_MS / 1000,
            buildUrl: ({ port, ticketId }) => {
                const url = new URL(`${config.serviceUrl}/plugin/trace-functions/${encodeURIComponent(functionKey)}/datasets/${encodeURIComponent(datasetId)}`);
                if (port !== null) {
                    url.searchParams.set("callbackPort", String(port));
                }
                if (ticketId !== null) {
                    url.searchParams.set("ticket", ticketId);
                }
                return url.toString();
            },
            loopbackRoutes: [loopbackRoute],
        });
        agentAbort.abort();
        await pollerPromise;
        const { status, decision, labeled, total, isFetch } = value;
        emitJson({ event: status, status, decision, labeled, total });
        if (status === "saved") {
            console.error(labeled && total
                ? `Labeling complete: ${labeled}/${total} traces labeled (last: ${decision ?? "labeled"}) [via ${wonBy}]`
                : `Labeling complete: ${decision ?? "labeled"} [via ${wonBy}]`);
        }
        else if (labeled && total && Number(labeled) > 0) {
            console.error(`Labeling ended early: ${labeled}/${total} traces labeled.`);
        }
        else {
            console.error("Labeling ended without saving.");
        }
        await reportHandoff(apiKey, pluginVersion, platform, {
            flow: "dataset.start",
            wonBy: wonBy,
            loopbackAvailable,
            ticketAvailable,
        });
        if (isFetch) {
            focusApp(previousApp);
        }
        process.exit(0);
    }
    catch (err) {
        agentAbort.abort();
        await pollerPromise.catch(() => { });
        console.error(err.message);
        process.exit(1);
    }
}
